16	function slurpStdin() {
17	  return new Promise((resolve, reject) => {
18	    let d = '';
19	    stdin.setEncoding('utf8');
20	    stdin.on('data', (c) => {
21	      d += c;
22	    });
23	    stdin.on('end', () => resolve(d));
24	    stdin.on('error', reject);
25	  });
26	}
27	
28	async function readPayloadOrStdin(pathArg) {
29	  if (pathArg && pathArg !== '-') {
30	    return fs.readFile(pathArg, 'utf8');
31	  }
32	  if (stdin.isTTY) {
33	    console.error('Pass a JSON file path, or pipe JSON on stdin (use - for explicit stdin).');
34	    process.exit(1);
35	  }
36	  return slurpStdin();
37	}
