46	function wsUrl(modelId) {
47	  const u = new URL(base);
48	  u.protocol = u.protocol === 'https:' ? 'wss:' : 'ws:';
49	  u.pathname = `/ws/${encodeURIComponent(modelId)}`;
50	  u.search = '';
51	  return u.href;
