74	async function fetchOkText(method, url) {
75	  const res = await fetch(url, {
76	    method,
77	    headers: { accept: 'model/gltf+json,application/json,text/plain;q=0.9,*/*;q=0.1' },
78	  });
79	  const text = await res.text();
80	  if (!res.ok) {
81	    console.error(JSON.stringify({ status: res.status, sample: text.slice(0, 2000) }, null, 2));
82	    process.exit(1);
83	  }
84	  return text;
85	}
