87	async function fetchOkBytes(method, url) {
88	  const res = await fetch(url, {
89	    method,
90	    headers: {
91	      accept:
92	        'application/octet-stream,model/gltf-binary,*/*;q=0.8',
93	    },
94	  });
95	  const buf = Buffer.from(await res.arrayBuffer());
96	  if (!res.ok) {
97	    console.error(JSON.stringify({ status: res.status, bytes: buf.length }, null, 2));
98	    process.exit(1);
99	  }
100	  return buf;
101	}
