177	async function cmdEvidence(modelId) {
178	  const snap = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`);
179	  const val = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/validate`);
180	  const els = snap.elements && typeof snap.elements === 'object' ? snap.elements : {};
181	  /** @type {Record<string, number>} */
182	  const counts = {};
183	  for (const id of Object.keys(els)) {
184	    const row = els[id];
185	    const k =
186	      row && typeof row === 'object' && typeof row.kind === 'string'
187	        ? row.kind
188	        : '?';
189	    counts[k] = (counts[k] ?? 0) + 1;
190	  }
191	  const out = {
192	    generatedAt: new Date().toISOString(),
193	    modelId,
194	    revision: snap.revision,
195	    elementCount: Object.keys(els).length,
196	    countsByKind: counts,
197	    validate: val,
198	  };
199	  console.log(JSON.stringify(out, null, 2));
200	}
