215	  const url = `${base}/api/models/${encodeURIComponent(modelId)}/schedules/${encodeURIComponent(scheduleId)}/table${qs}`;
216	  const res = await fetch(url);
217	  const text = await res.text();
218	
219	  let json;
220	
221	  try {
222	    json = JSON.parse(text);
223	  } catch {
224	    json = undefined;
225	  }
226	
227	  if (!res.ok) {
228	    console.error(JSON.stringify({ status: res.status, body: json ?? text }, null, 2));
229	
230	    process.exit(1);
