269	function validateHouseBrief(blob) {
270	  const errors = [];
271	  if (!blob || typeof blob !== 'object') {
272	    errors.push('brief must be a JSON object');
273	    return errors;
274	  }
275	  if (typeof blob.version !== 'string') errors.push('version (string)');
276	  if (blob.stylePreset != null && typeof blob.stylePreset !== 'string')
277	    errors.push('stylePreset (optional string)');
278	  if (!Number.isFinite(blob.siteWidthM)) errors.push('siteWidthM (number)');
279	  if (!Number.isFinite(blob.siteDepthM)) errors.push('siteDepthM (number)');
280	  const floors = blob.floors;
281	  if (!Number.isInteger(floors) || floors < 1) errors.push('floors (int >= 1)');
282	  const rooms = blob.rooms;
283	  if (!Array.isArray(rooms) || rooms.length === 0) errors.push('rooms (non-empty array)');
284	  else {
285	    rooms.forEach((r, i) => {
286	      if (!r || typeof r !== 'object') errors.push(`rooms[${i}] object`);
287	      else {
288	        if (typeof r.name !== 'string') errors.push(`rooms[${i}].name`);
289	        if (!Number.isFinite(r.areaTargetM2)) errors.push(`rooms[${i}].areaTargetM2`);
290	      }
291	    });
292	  }
293	  return errors;
294	}
