296	function briefToHouseStarterBundle(brief, modelIdPlaceholder) {
297	  const commands = buildOneFamilyHomeCommands();
298	  return {
299	    meta: {
300	      generatedBy: '@bim-ai/cli plan-house',
301	      modelIdPlaceholder,
302	      note:
303	        'Fixed one-family footprint (shared with scripts/apply-one-family-home.mjs). Use on empty model — do not prepend deleteElements when applying to a seeded demo.',
304	      brief,
305	    },
306	    commands,
307	  };
