310	async function cmdPlanHouse(briefPath, outPath, modelHint) {
311	  const raw = (await fs.readFile(briefPath, 'utf8')).trim();
312	  let brief;
313	  try {
314	    brief = JSON.parse(raw);
315	  } catch {
316	    console.error(`Invalid JSON: ${briefPath}`);
317	    process.exit(1);
318	  }
319	  const err = validateHouseBrief(brief);
320	  if (err.length) {
321	    console.error(JSON.stringify({ ok: false, errors: err }, null, 2));
322	    process.exit(1);
323	  }
324	  const bundle = briefToHouseStarterBundle(brief, modelHint ?? '${BIM_AI_MODEL_ID}');
325	  await fs.mkdir(path.dirname(outPath), { recursive: true });
326	  await fs.writeFile(outPath, `${JSON.stringify(bundle, null, 2)}\n`, 'utf8');
327	  console.log(JSON.stringify({ ok: true, out: outPath, commandCount: bundle.commands.length }, null, 2));
328	}
