330	async function cmdExport(kind, modelId, outPath) {
331	  if (kind === 'gltf') {
332	    if (!modelId) usage();
333	    const url = `${base}/api/models/${encodeURIComponent(modelId)}/exports/model.gltf`;
334	    const text = await fetchOkText('GET', url);
335	    if (outPath && outPath !== '-') {
336	      await fs.writeFile(outPath, text, 'utf8');
337	      console.log(JSON.stringify({ ok: true, out: outPath, chars: text.length }, null, 2));
338	    } else {
339	      process.stdout.write(text);
340	      if (!text.endsWith('\n')) process.stdout.write('\n');
341	    }
342	    return;
343	  }
344	  if (kind === 'glb') {
345	    if (!modelId) usage();
346	    const url = `${base}/api/models/${encodeURIComponent(modelId)}/exports/model.glb`;
347	    const buf = await fetchOkBytes('GET', url);
348	    if (outPath && outPath !== '-') {
349	      await fs.writeFile(outPath, buf);
350	      console.log(JSON.stringify({ ok: true, out: outPath, bytes: buf.length }, null, 2));
351	    } else {
352	      process.stdout.write(buf);
353	    }
354	    return;
355	  }
356	  if (kind === 'ifc') {
357	    if (!modelId) usage();
358	    const url = `${base}/api/models/${encodeURIComponent(modelId)}/exports/model.ifc`;
359	    const buf = await fetchOkBytes('GET', url);
360	    if (outPath && outPath !== '-') {
361	      await fs.writeFile(outPath, buf);
362	      console.log(JSON.stringify({ ok: true, out: outPath, bytes: buf.length }, null, 2));
363	    } else {
364	      process.stdout.write(buf.toString('utf8'));
365	    }
366	    return;
367	  }
368	  console.error(`export ${kind}: not implemented (see spec/workpackage-master-tracker.md backlog).`);
369	  process.exit(2);
370	}
