377	function usage() {
378	  console.error(
379	    `bim-ai <command> [args]
380	
381	Commands:
382	  bootstrap                           GET /api/bootstrap (projects + models)
383	  init-model --project-id <uuid> [--slug slug]
384	                                       POST empty model row (agents use BIM_AI_MODEL_ID from output)
385	  schema                              GET /api/schema (commands + presets ids)
386	  presets                             summarize schema + building presets
387	  snapshot                            GET snapshot (needs BIM_AI_MODEL_ID)
388	  evidence                            Combined artifact: counts-by-kind + full validate rollup
389	  evidence-package                    Phase A checklist JSON (captures recommended layouts + manifests)
390	  schedule-table [--csv] [--columns keys] <scheduleId>   Server-derived rows (optional CSV; columns=comma-separated keys)
391	  export-manifests                     glTF + IFC exchange-manifest JSON stubs
392	  export gltf [--out <path>]           download model.gltf JSON (default: stdout; needs BIM_AI_MODEL_ID)
393	  export glb [--out <path>]            download model.glb binary (default: stdout; needs BIM_AI_MODEL_ID)
394	  export ifc [--out <path>]            download model.ifc (default: stdout; needs BIM_AI_MODEL_ID)
395	  summary                             GET model summary rollup
396	  validate                            GET violations + summary + counts
397	  command-log [limit]                  GET undo/command history with full commands JSON
398	  apply [file|-]                       POST single command
399	  apply-bundle [file|-]                POST bundle
400	  apply-bundle --dry-run [file|-]      POST bundle dry-run (no commit)
401	  dry-run [file|-]                     POST single command dry-run
402	  plan-house --brief <path> --out <path> [--model-hint id]
403	                                       validate brief JSON → write starter command bundle (one-family preset)
404	  export json                          reserved (stub)
405	  diff --from … --to …                 reserved (stub)
406	  watch                               WebSocket watcher
407	
408	Env:
409	  BIM_AI_MODEL_ID   (required for model-scoped ops)
410	  BIM_AI_USER_ID    default: local-dev
411	  BIM_AI_BASE_URL   default: http://127.0.0.1:8500`,
412	  );
413	  process.exit(1);
414	}
