416	async function main() {
417	  let argv = process.argv.slice(2);
418	  let modelId = process.env.BIM_AI_MODEL_ID;
419	  const userId = process.env.BIM_AI_USER_ID ?? 'local-dev';
420	
421	  if (!argv.length) usage();
422	  let cmd = argv[0];
423	
424	  if (argv[0] === 'apply-bundle' && argv[1] === '--dry-run') {
425	    cmd = '__apply-bundle-dry';
426	    argv = argv.slice(2);
427	  }
428	
429	  try {
430	    if (cmd === 'bootstrap') {
431	      await cmdBootstrapCli();
432	      return;
433	    }
434	    if (cmd === 'init-model') {
435	      const rest = argv.slice(1);
436	      let pid;
437	      let slug = `empty-${Date.now().toString(36)}`;
438	      for (let i = 0; i < rest.length; i++) {
439	        const a = rest[i];
440	        if (a === '--project-id' && rest[i + 1]) pid = rest[++i];
441	        else if (a === '--slug' && rest[i + 1]) slug = rest[++i];
442	      }
443	      if (!pid) {
444	        console.error('init-model requires --project-id <uuid> (run bim-ai bootstrap first).');
445	        usage();
446	      }
447	      await cmdInitModel(pid, slug);
448	      return;
449	    }
450	    if (cmd === 'schema') {
451	      await cmdSchema();
452	      return;
453	    }
454	    if (cmd === 'presets') {
455	      await cmdPresets();
456	      return;
457	    }
458	    if (cmd === 'summary') {
459	      if (!modelId) usage();
460	      await cmdSummary(modelId);
461	      return;
462	    }
463	    if (cmd === 'validate') {
464	      if (!modelId) usage();
465	      await cmdValidate(modelId);
466	      return;
467	    }
468	    if (cmd === 'evidence') {
469	      if (!modelId) usage();
470	      await cmdEvidence(modelId);
471	      return;
472	    }
473	    if (cmd === 'evidence-package') {
474	      if (!modelId) usage();
475	      await cmdEvidencePackage(modelId);
476	      return;
477	    }
478	    if (cmd === 'export-manifests') {
479	      if (!modelId) usage();
480	      await cmdExportManifests(modelId);
481	      return;
482	    }
483	    if (cmd === 'schedule-table') {
484	      if (!modelId) usage();
485	      const args = argv.slice(1);
486	      let wantCsv = false;
487	      let columnsArg;
488	      let sid;
489	      for (let i = 0; i < args.length; i++) {
490	        const a = args[i];
491	        if (a === '--csv') wantCsv = true;
492	        else if (a === '--columns' && args[i + 1]) columnsArg = args[++i];
493	        else if (!a.startsWith('-')) sid = sid ?? a;
494	      }
495	      if (!sid) usage();
496	      await cmdScheduleTable(modelId, sid, wantCsv, columnsArg);
497	      return;
498	    }
499	    if (cmd === 'command-log') {
500	      if (!modelId) usage();
501	      const lim = argv[1] ? Number(argv[1]) : undefined;
502	      await cmdCommandLog(modelId, Number.isFinite(lim) ? lim : undefined);
503	      return;
504	    }
505	    if (cmd === 'plan-house') {
506	      let briefArg;
507	      let outArg;
508	      let modelHint;
509	      const rest = argv.slice(1);
510	      for (let i = 0; i < rest.length; i++) {
511	        const a = rest[i];
512	        if (a === '--brief' && rest[i + 1]) briefArg = rest[++i];
513	        else if (a === '--out' && rest[i + 1]) outArg = rest[++i];
514	        else if (a === '--model-hint' && rest[i + 1]) modelHint = rest[++i];
515	      }
516	      if (!briefArg || !outArg) usage();
517	      await cmdPlanHouse(briefArg, outArg, modelHint);
518	      return;
519	    }
520	
521	    const pathArgFirst = argv[1];
522	    const pathArgDry = argv[1];
523	
524	    if (cmd === 'export') {
525	      const rest = argv.slice(1);
526	      const k = rest[0];
527	      if (!k) usage();
528	      let outArg;
529	      for (let i = 1; i < rest.length; i++) {
530	        if (rest[i] === '--out' && rest[i + 1]) outArg = rest[++i];
531	      }
532	      await cmdExport(k, modelId, outArg);
533	      return;
534	    }
535	    if (cmd === 'diff') {
536	      await cmdDiff();
537	      return;
538	    }
539	
540	    if (!modelId && cmd !== 'schema' && cmd !== 'presets' && cmd !== 'plan-house' && cmd !== 'bootstrap' && cmd !== 'init-model')
541	      usage();
542	
543	    if (cmd === 'snapshot') {
544	      await snapshot(modelId);
545	      return;
546	    }
547	
548	    if (cmd === 'apply') {
549	      const raw = (await readPayloadOrStdin(pathArgFirst)).trim();
550	      if (!raw) {
551	        console.error('Empty JSON for apply');
552	        process.exit(1);
553	      }
554	      await postCommand(modelId, userId, JSON.parse(raw));
555	      return;
556	    }
557	
558	    if (cmd === 'dry-run') {
559	      const raw = (await readPayloadOrStdin(pathArgDry)).trim();
560	      if (!raw) {
561	        console.error('Empty JSON for dry-run');
562	        process.exit(1);
563	      }
564	      await dryRunCommand(modelId, userId, JSON.parse(raw));
565	      return;
566	    }
567	
568	    if (cmd === 'apply-bundle') {
569	      const raw = (await readPayloadOrStdin(pathArgFirst)).trim();
570	      if (!raw) {
571	        console.error('Empty JSON for apply-bundle');
572	        process.exit(1);
573	      }
574	      const cmds = commandsFromBundleJson(JSON.parse(raw));
575	      await postBundle(modelId, userId, cmds);
576	      return;
577	    }
578	
579	    if (cmd === '__apply-bundle-dry') {
580	      const pathArg = argv[0];
581	      const raw = (await readPayloadOrStdin(pathArg)).trim();
582	      if (!raw) {
583	        console.error('Empty JSON for apply-bundle --dry-run');
584	        process.exit(1);
585	      }
586	      const cmds = commandsFromBundleJson(JSON.parse(raw));
587	      await dryRunBundle(modelId, userId, cmds);
588	      return;
589	    }
590	
591	    if (cmd === 'watch') {
592	      const url = wsUrl(modelId);
593	      console.error(`Watching ${url}`);
594	      const ws = new WebSocket(url);
595	      ws.addEventListener('open', () => {
596	        const ping = { type: 'presence_update', peerId: 'cli', userId, name: 'bim-ai-cli' };
